package dev.harrison.rendacomcarro;
import dev.harrison.rendacomcarro.dashboard.application.DashboardService;import dev.harrison.rendacomcarro.finance.application.*;import dev.harrison.rendacomcarro.finance.domain.*;import dev.harrison.rendacomcarro.goal.application.GoalService;import dev.harrison.rendacomcarro.operation.application.*;import dev.harrison.rendacomcarro.operation.domain.*;import dev.harrison.rendacomcarro.operation.infrastructure.PlatformRepository;import dev.harrison.rendacomcarro.support.PostgresIntegrationTest;import dev.harrison.rendacomcarro.vehicle.application.VehicleService;import dev.harrison.rendacomcarro.vehicle.domain.FuelType;import java.math.*;import java.time.*;import java.util.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.test.context.TestPropertySource;import static org.assertj.core.api.Assertions.assertThat;
@SpringBootTest@TestPropertySource(properties={"APP_ADMIN_USERNAME=acceptance-owner","APP_ADMIN_PASSWORD=acceptance-owner-credential"})class AcceptanceFlowTest extends PostgresIntegrationTest {@Autowired VehicleService vehicles;@Autowired GoalService goals;@Autowired OperationalDayService days;@Autowired ShiftService shifts;@Autowired RevenueService revenues;@Autowired PlatformRepository platforms;@Autowired FinancialObligationService obligations;@Autowired DashboardService dashboard;
@Test void ownerCanExecuteCoreOperationalAndFinancialFlow(){LocalDate date=LocalDate.now();var vehicle=vehicles.create(new VehicleService.CreateVehicleCommand("Carro aceite","Honda","Fit",2016,"ACC1A23",FuelType.FLEX,new BigDecimal("50000"),new BigDecimal("45000")));vehicles.activateAsPrimary(vehicle.getId());if(goals.find(YearMonth.from(date)).isEmpty())goals.create(YearMonth.from(date),new BigDecimal("2100"),new BigDecimal("5000"),new BigDecimal("160"),Set.of(date.getDayOfWeek()==DayOfWeek.SUNDAY?date.plusDays(1):date));var day=days.openDay(date,vehicle.getId(),new BigDecimal("200"),new BigDecimal("50000"));var uber=platforms.findByCode("UBER").orElseThrow();var shift=shifts.openShift(day.getId(),LocalDateTime.now().minusHours(2),new BigDecimal("50000"),"Centro",Set.of(uber.getId()));revenues.create(new RevenueService.CreateRevenueCommand(shift.getId(),null,uber.getId(),RevenueType.CONSOLIDATED,date,date,null,null,new BigDecimal("250"),BigDecimal.ZERO,BigDecimal.ZERO,DataSource.MANUAL,"ACC-REV"));shifts.closeShift(shift.getId(),LocalDateTime.now(),new BigDecimal("50080"),"Pampulha",Set.of("Centro","Pampulha"));var debt=obligations.create(new FinancialObligationService.CreateCommand(vehicle.getId(),ObligationType.FAMILY_LOAN,ObligationMode.FLEXIBLE,"Família",new BigDecimal("30000"),BigDecimal.ZERO,date,null,null,null,new BigDecimal("500"),null));obligations.pay(debt.getId(),date,new BigDecimal("500"),BigDecimal.ZERO,BigDecimal.ZERO,"ACC-PAY",null);days.closeDay(day.getId(),new BigDecimal("50080"));var snapshot=dashboard.snapshot(date);assertThat(snapshot.dailyRevenue()).isEqualByComparingTo("250.00");assertThat(snapshot.outstandingDebt()).isEqualByComparingTo("29500.00");}}
